package ly.com.tahaben.flavorizr.util

object FileMarker {
    private const val PREFIX = "kmp-flavorizr"

    fun beginMarker(section: String): String =
        "// ----- BEGIN $section (autogenerated by $PREFIX) -----"

    fun endMarker(section: String): String =
        "// ----- END $section (autogenerated by $PREFIX) -----"

    /**
     * Replaces an existing marked section, or inserts a new one after [insertAfterPattern].
     * Returns the modified content.
     */
    fun replaceOrInsert(
        content: String,
        section: String,
        replacement: String,
        insertAfterPattern: Regex,
    ): String {
        val begin = beginMarker(section)
        val end = endMarker(section)

        // Check if markers already exist
        if (content.contains(begin) && content.contains(end)) {
            val pattern = Regex(
                Regex.escape(begin) + ".*?" + Regex.escape(end),
                RegexOption.DOT_MATCHES_ALL,
            )
            return content.replace(pattern, "$begin\n$replacement\n$end")
        }

        // Insert after pattern
        val match = insertAfterPattern.find(content)
            ?: throw IllegalStateException(
                "Could not find insertion point matching pattern '${insertAfterPattern.pattern}' for section '$section'"
            )

        val insertionPoint = match.range.last + 1
        return buildString {
            append(content.substring(0, insertionPoint))
            append("\n")
            append(begin)
            append("\n")
            append(replacement)
            append("\n")
            append(end)
            append(content.substring(insertionPoint))
        }
    }

    /**
     * Replaces an existing marked section, or appends to the end.
     */
    fun replaceOrAppend(
        content: String,
        section: String,
        replacement: String,
    ): String {
        val begin = beginMarker(section)
        val end = endMarker(section)

        if (content.contains(begin) && content.contains(end)) {
            val pattern = Regex(
                Regex.escape(begin) + ".*?" + Regex.escape(end),
                RegexOption.DOT_MATCHES_ALL,
            )
            return content.replace(pattern, "$begin\n$replacement\n$end")
        }

        return buildString {
            append(content.trimEnd())
            append("\n\n")
            append(begin)
            append("\n")
            append(replacement)
            append("\n")
            append(end)
            append("\n")
        }
    }
}
